function solve(nums: number[], queries: number[][]): number[] {
    const indexMap = new Map<number, number[]>();
    for (let i = 0; i < nums.length; i++) {
        const num = nums[i];
        if (!indexMap.has(num)) {
            indexMap.set(num, []);
        }
        indexMap.get(num).push(i);
    }

    const bisectLeft = (arr: number[], target: number): number => {
        let left = 0, right = arr.length;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (arr[mid] < target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    };

    const bisectRight = (arr: number[], target: number): number => {
        let left = 0, right = arr.length;
        while (left < right) {
            const mid = Math.floor((left + right) / 2);
            if (arr[mid] <= target) {
                left = mid + 1;
            } else {
                right = mid;
            }
        }
        return left;
    };

    const ans: number[] = [];
    for (const query of queries) {
        const [li, ri, threshold] = query;
        const candidates: { x: number, count: number }[] = [];
        for (const [x, indices] of indexMap.entries()) {
            const total = indices.length;
            if (total < threshold) continue;
            const left = bisectLeft(indices, li);
            const right = bisectRight(indices, ri);
            const count = right - left;
            if (count >= threshold) {
                candidates.push({ x, count });
            }
        }
        if (candidates.length === 0) {
            ans.push(-1);
            continue;
        }
        let maxCount = -1;
        let bestX = -1;
        for (const { x, count } of candidates) {
            if (count > maxCount) {
                maxCount = count;
                bestX = x;
            } else if (count === maxCount) {
                if (x < bestX) {
                    bestX = x;
                }
            }
        }
        ans.push(bestX);
    }
    return ans;
}
